class Session {
public:
    std::string data;
    std::chrono::steady_clock::time_point expiry_time;

    Session(std::string data, std::chrono::seconds duration)
        : data(data), expiry_time(std::chrono::steady_clock::now() + duration) {}
};

class CachingSystem {
private:
    std::unordered_map<std::string, Session*> cache;
    std::unordered_map<std::string, bool> session_ids;

public:
    void createSession(const std::string& sessionId, const std::string& data, std::chrono::seconds duration) {
        if (session_ids.find(sessionId) != session_ids.end()) return;
        session_ids[sessionId] = true;
        cache[sessionId] = new Session(data, duration);
    }

    std::string accessSession(const std::string& sessionId) {
        if (!isValidSession(sessionId)) return "";
        return cache[sessionId]->data;
    }

    void invalidateSession(const std::string& sessionId) {
        if (session_ids.find(sessionId) == session_ids.end()) return;
        session_ids.erase(sessionId);
        delete cache[sessionId];
        cache.erase(sessionId);
    }

private:
    bool isValidSession(const std::string& sessionId) {
        if (cache.find(sessionId) == cache.end() || !session_ids[sessionId]) return false;
        if (std::chrono::steady_clock::now() > cache[sessionId]->expiry_time) {
            session_ids.erase(sessionId);
            delete cache[sessionId];
            cache.erase(sessionId);
            return false;
        }
        return true;
    }
};

